const now = $now.setZone("America/Sao_Paulo");
const execution_id = `EXEC-${now.toFormat("yyyyLLdd-HHmmss")}`;

return [{
  json: {
    execution_id,
    source_execution_id: execution_id,
    client_id: null
  }
}];

const errorValue = $json.error ?? $json.executionError ?? $json.stack ?? null;
const errorMessage =
  typeof errorValue === "string"
    ? errorValue
    : errorValue?.message || $json.message || "Falha sem mensagem retornada";

return [{
  json: {
    ...$json,
    alert_type: "subworkflow_failure",
    failed_subworkflow: "sw metricas campanhas",
    alert_message: "Falha no subworkflow: sw metricas campanhas",
    alert_details: errorMessage
  }
}];

